<?php
namespace App\Services\Security;
use App\Models\{SecurityIncident,SecurityIncidentEvidenceLink,SecurityIncidentPlaybook,SecurityIncidentPlaybookRun,SecurityIncidentTask,User};use Illuminate\Validation\ValidationException;
class SecurityIncidentResponseService{public function linkEvidence(SecurityIncident $i,User $a,string $type,?string $id,array $d):SecurityIncidentEvidenceLink{$allowed=['governance_notification','audit_export','audit_export_retention_job','worker_payout_evidence','evidence_retention_job','reviewer_access','access_review_cycle','scanner_event','manual_note'];if(!in_array($type,$allowed,true))throw ValidationException::withMessages(['type'=>'Supported masked evidence link type is required.']);$summary=str_replace(['stored_path','file_path'],'[masked]',(string)($d['summary']??''));$l=SecurityIncidentEvidenceLink::create(['security_incident_id'=>$i->id,'linked_type'=>$type,'linked_id'=>$id,'label'=>$d['label']??null,'visibility'=>$d['visibility']??'internal','summary'=>$summary,'added_by_id'=>$a->id,'added_at'=>now()]);$this->event($i,$a,'source_linked',"{$type}: {$summary}");return $l;}public function addTask(SecurityIncident $i,User $a,array $d):SecurityIncidentTask{$t=SecurityIncidentTask::create(['security_incident_id'=>$i->id,'title'=>$d['title'],'description'=>$d['description']??null,'priority'=>$d['priority']??'normal','assigned_to_id'=>$d['assigned_to_id']??null,'due_at'=>$d['due_at']??null]);$this->event($i,$a,'note_added',"Task added: {$t->title}");return $t;}public function assignTask($t,User $a,User $assignee,string $reason){$t->update(['assigned_to_id'=>$assignee->id,'status'=>'in_progress']);$this->event(SecurityIncident::find($t->security_incident_id),$a,'assigned',$reason);return $t->refresh();}public function completeTask($t,User $a,string $note){$t->update(['status'=>'completed','completed_by_id'=>$a->id,'completed_at'=>now(),'completion_note'=>$note]);$this->event(SecurityIncident::find($t->security_incident_id),$a,'note_added',"Task completed: {$t->title}");return $t->refresh();}public function blockTask($t,User $a,string $reason){$t->update(['status'=>'blocked','blocked_reason'=>$reason]);$this->event(SecurityIncident::find($t->security_incident_id),$a,'note_added',"Task blocked: {$reason}");return $t->refresh();}public function skipTask($t,User $a,string $reason){$t->update(['status'=>'skipped','completion_note'=>$reason]);$this->event(SecurityIncident::find($t->security_incident_id),$a,'note_added',"Task skipped: {$reason}");return $t->refresh();}public function applyPlaybook(SecurityIncident $i,SecurityIncidentPlaybook $p,User $a):SecurityIncidentPlaybookRun{$run=SecurityIncidentPlaybookRun::create(['security_incident_id'=>$i->id,'security_incident_playbook_id'=>$p->id,'status'=>'started','started_by_id'=>$a->id,'started_at'=>now()]);foreach($p->steps??[] as $step)$this->addTask($i,$a,['title'=>$step,'priority'=>$i->severity==='critical'?'critical':'normal']);$this->event($i,$a,'note_added',"Playbook applied: {$p->name}");return $run;}public function buildTimeline(SecurityIncident $i):array{return collect()->concat($i->events->map(fn($e)=>['at'=>$e->created_at,'type'=>'event','summary'=>$e->description]))->concat($i->evidenceLinks->map(fn($e)=>['at'=>$e->added_at,'type'=>'evidence_link','summary'=>$e->summary]))->concat($i->tasks->map(fn($t)=>['at'=>$t->updated_at,'type'=>'task','summary'=>"{$t->title}: {$t->status}"]))->sortBy('at')->values()->all();}private function event($i,$a,$t,$d){$i->events()->create(['actor_id'=>$a->id,'event_type'=>$t,'description'=>$d,'created_at'=>now()]);}}
